layer_0_fused_mbr:
    subu  $sp, $sp, 32
    sw    $ra, 28($sp)
    sw    $fp, 24($sp)
    sw    $s0, 20($sp)
    sw    $s1, 16($sp)
    sw    $s2, 12($sp)
    sw    $s3, 8($sp)
    sw    $s4, 4($sp)
    addiu $fp, $sp, 32

    # MatMul (standard loops): 64 outputs x 784 inputs
    la    $t8, layer_0_weights
    la    $t9, layer_0_biases
    move  $t7, $s0
    move  $t6, $s1
    li    $s2, 0
layer_0_fused_mbr_oloop:
    bge   $s2, 64, layer_0_fused_mbr_oend
    sll   $t0, $s2, 2
    add   $t0, $t9, $t0
    lwc1  $f0, 0($t0)
    li    $s3, 0
layer_0_fused_mbr_iloop:
    bge   $s3, 784, layer_0_fused_mbr_iend
    sll   $t1, $s3, 2
    add   $t1, $t7, $t1
    lwc1  $f2, 0($t1)
    mul   $t2, $s3, 64
    add   $t2, $t2, $s2
    sll   $t2, $t2, 2
    add   $t2, $t8, $t2
    lwc1  $f4, 0($t2)
    mul.s $f6, $f2, $f4
    add.s $f0, $f0, $f6
    addi  $s3, $s3, 1
    j     layer_0_fused_mbr_iloop
layer_0_fused_mbr_iend:
    lwc1  $f2, fpu_zero
    c.lt.s $f0, $f2
    bc1f  layer_0_fused_mbr_relu_skip
    mov.s $f0, $f2
layer_0_fused_mbr_relu_skip:
    sll   $t1, $s2, 2
    add   $t1, $t6, $t1
    swc1  $f0, 0($t1)
    addi  $s2, $s2, 1
    j     layer_0_fused_mbr_oloop
layer_0_fused_mbr_oend:


    lw    $ra, 28($sp)
    lw    $fp, 24($sp)
    lw    $s0, 20($sp)
    lw    $s1, 16($sp)
    lw    $s2, 12($sp)
    lw    $s3, 8($sp)
    lw    $s4, 4($sp)
    addiu $sp, $sp, 32
    jr    $ra

layer_1_fused_mb:
    subu  $sp, $sp, 32
    sw    $ra, 28($sp)
    sw    $fp, 24($sp)
    sw    $s0, 20($sp)
    sw    $s1, 16($sp)
    sw    $s2, 12($sp)
    sw    $s3, 8($sp)
    sw    $s4, 4($sp)
    addiu $fp, $sp, 32

    # MatMul (standard loops): 10 outputs x 64 inputs
    la    $t8, layer_1_weights
    la    $t9, layer_1_biases
    move  $t7, $s0
    move  $t6, $s1
    li    $s2, 0
layer_1_fused_mb_oloop:
    bge   $s2, 10, layer_1_fused_mb_oend
    sll   $t0, $s2, 2
    add   $t0, $t9, $t0
    lwc1  $f0, 0($t0)
    li    $s3, 0
layer_1_fused_mb_iloop:
    bge   $s3, 64, layer_1_fused_mb_iend
    sll   $t1, $s3, 2
    add   $t1, $t7, $t1
    lwc1  $f2, 0($t1)
    mul   $t2, $s3, 10
    add   $t2, $t2, $s2
    sll   $t2, $t2, 2
    add   $t2, $t8, $t2
    lwc1  $f4, 0($t2)
    mul.s $f6, $f2, $f4
    add.s $f0, $f0, $f6
    addi  $s3, $s3, 1
    j     layer_1_fused_mb_iloop
layer_1_fused_mb_iend:
    sll   $t1, $s2, 2
    add   $t1, $t6, $t1
    swc1  $f0, 0($t1)
    addi  $s2, $s2, 1
    j     layer_1_fused_mb_oloop
layer_1_fused_mb_oend:


    lw    $ra, 28($sp)
    lw    $fp, 24($sp)
    lw    $s0, 20($sp)
    lw    $s1, 16($sp)
    lw    $s2, 12($sp)
    lw    $s3, 8($sp)
    lw    $s4, 4($sp)
    addiu $sp, $sp, 32
    jr    $ra

layer_1_act:
    subu  $sp, $sp, 32
    sw    $ra, 28($sp)
    sw    $fp, 24($sp)
    sw    $s0, 20($sp)
    sw    $s1, 16($sp)
    sw    $s2, 12($sp)
    sw    $s3, 8($sp)
    sw    $s4, 4($sp)
    addiu $fp, $sp, 32

    # Softmax activation
    move  $a0, $s0
    li    $a1, 10
    jal   fpu_vec_max
    mov.s $f12, $f0
    li    $t4, 0
    lwc1  $f2, exp_clamp_neg
    lwc1  $f4, fpu_zero
layer_1_act_sm_loop:
    bge   $t4, 10, layer_1_act_sm_sum
    sll   $t5, $t4, 2
    add   $t5, $s0, $t5
    lwc1  $f0, 0($t5)
    sub.s $f0, $f0, $f12
    sw    $t4, -4($sp)
    sw    $t5, -8($sp)
    jal   fpu_exp
    lw    $t4, -4($sp)
    lw    $t5, -8($sp)
    swc1  $f0, 0($t5)
    addi  $t4, $t4, 1
    j     layer_1_act_sm_loop
layer_1_act_sm_sum:
    move  $a0, $s0
    li    $a1, 10
    jal   fpu_vec_sum
    mov.s $f12, $f0
    li    $t4, 0
layer_1_act_sm_div:
    bge   $t4, 10, layer_1_act_sm_done
    sll   $t5, $t4, 2
    add   $t5, $s0, $t5
    lwc1  $f0, 0($t5)
    div.s $f0, $f0, $f12
    swc1  $f0, 0($t5)
    addi  $t4, $t4, 1
    j     layer_1_act_sm_div
layer_1_act_sm_done:


    lw    $ra, 28($sp)
    lw    $fp, 24($sp)
    lw    $s0, 20($sp)
    lw    $s1, 16($sp)
    lw    $s2, 12($sp)
    lw    $s3, 8($sp)
    lw    $s4, 4($sp)
    addiu $sp, $sp, 32
    jr    $ra

print_output:
    move  $t8, $a0
    li    $t2, 0
print_output_loop:
    bge   $t2, 10, print_output_end
    sll   $t3, $t2, 2
    add   $t3, $t8, $t3
    lwc1  $f12, 0($t3)
    li    $v0, 2
    syscall
    li    $a0, 10
    li    $v0, 11
    syscall
    addi  $t2, $t2, 1
    j     print_output_loop
print_output_end:
    jr    $ra

memcpy:
    li    $t0, 0
memcpy_loop:
    bge   $t0, $a2, memcpy_end
    add   $t1, $a1, $t0
    lw    $t2, 0($t1)
    add   $t1, $a0, $t0
    sw    $t2, 0($t1)
    addi  $t0, $t0, 4
    j     memcpy_loop
memcpy_end:
    jr    $ra

vec_max:
    lw    $v0, 0($a0)
    li    $t0, 1
vec_max_loop:
    bge   $t0, $a1, vec_max_end
    sll   $t1, $t0, 2
    add   $t1, $a0, $t1
    lw    $t2, 0($t1)
    slt   $t3, $v0, $t2
    beq   $t3, $zero, vec_max_skip
    move  $v0, $t2
vec_max_skip:
    addi  $t0, $t0, 1
    j     vec_max_loop
vec_max_end:
    jr    $ra

vec_sum:
    li    $v0, 0
    li    $t0, 0
vec_sum_loop:
    bge   $t0, $a1, vec_sum_end
    sll   $t1, $t0, 2
    add   $t1, $a0, $t1
    lw    $t2, 0($t1)
    add   $v0, $v0, $t2
    addi  $t0, $t0, 1
    j     vec_sum_loop
vec_sum_end:
    jr    $ra

fpu_vec_max:
    lwc1  $f0, 0($a0)
    li    $t0, 1
fpu_vec_max_loop:
    bge   $t0, $a1, fpu_vec_max_end
    sll   $t1, $t0, 2
    add   $t1, $a0, $t1
    lwc1  $f2, 0($t1)
    c.lt.s $f0, $f2
    bc1f  fpu_vec_max_skip
    mov.s $f0, $f2
fpu_vec_max_skip:
    addi  $t0, $t0, 1
    j     fpu_vec_max_loop
fpu_vec_max_end:
    jr    $ra

fpu_vec_sum:
    lwc1  $f0, fpu_zero
    li    $t0, 0
fpu_vec_sum_loop:
    bge   $t0, $a1, fpu_vec_sum_end
    sll   $t1, $t0, 2
    add   $t1, $a0, $t1
    lwc1  $f2, 0($t1)
    add.s $f0, $f0, $f2
    addi  $t0, $t0, 1
    j     fpu_vec_sum_loop
fpu_vec_sum_end:
    jr    $ra

    # e^x approx (Taylor): 1 + x + x^2/2 + x^3/6 + x^4/24
fpu_exp:
    lwc1  $f2, exp_clamp_neg
    c.lt.s $f0, $f2
    bc1f  fpu_exp_check_pos
    lwc1  $f0, fpu_zero
    jr    $ra
fpu_exp_check_pos:
    lwc1  $f2, exp_clamp_pos
    c.lt.s $f2, $f0
    bc1f  fpu_exp_calc
    mov.s $f0, $f2
fpu_exp_calc:
    mov.s $f2, $f0
    lwc1  $f4, exp_c4
    mul.s $f6, $f4, $f2
    lwc1  $f4, exp_c3
    add.s $f6, $f6, $f4
    mul.s $f6, $f6, $f2
    lwc1  $f4, exp_c2
    add.s $f6, $f6, $f4
    mul.s $f6, $f6, $f2
    lwc1  $f4, exp_c1
    add.s $f6, $f6, $f4
    mul.s $f6, $f6, $f2
    lwc1  $f4, exp_c0
    add.s $f0, $f6, $f4
    jr    $ra
